/// id is the running processor, now start others
#[allow(unused)]
fn processor_start(id: usize) {
    let nums = MAX_PROCESSORS;
    for i in 0..nums {
        if i == id {
            continue;
        }
        Instruction::hart_start(i, 0);
        // info!("[kernel] start to wake up processor {}... ",i);
    }
}

/// the rust entry-point of os
/// return true if need reboot (but not supported yet)
fn main(id: usize, first: bool) -> bool {
    if first {
        info!("id: {id}");
        banner::print_banner();
        processor::processor::init(id);
        hal::trap::init();
        devices::init();
        fs::init();
        // fs::vfs::file::list_apps();
        // fs::ext4::page_cache_test();
        #[cfg(not(feature = "smp"))]
        executor::init();
        task::schedule::spawn_kernel_task(async move {
            task::add_initproc();
        });

        #[cfg(feature = "smp")]
        processor_start(id);
    } else {
        processor::processor::init(id);
        hal::trap::init();
    }
    info!("[kernel] -------hart {} start-------", id);
    unsafe {
        Instruction::enable_timer_interrupt();
    }
    timer::set_next_trigger();
    executor::run_until_shutdown();
    // return false: HAL will shutdown
    false
}

fn enable_kvm() {
    KVMSPACE.lock().enable();
}

#[cfg(target_arch = "loongarch64")]
fn pre_main(id: usize, first: bool) -> bool {
    if first {
        mm::init();
    } else {
        enable_kvm();
    }
    main(id, first)
}

/// RISC-V 进入内核主逻辑前的过渡入口。
///
/// 这里仍运行在裸函数环境，不能依赖 Rust 自动生成的函数序言。代码先调用
/// 内存管理初始化或启用内核页表，再把当前栈迁移到高半区内核栈，最后调用
/// 普通 Rust 函数 `main`。
#[cfg(target_arch = "riscv64")]
#[naked]
extern "C" fn pre_main(id: usize, first: bool) -> bool {
    unsafe {
        naked_asm!(
            "
            # 保存进入时的临时栈指针；函数返回前需要恢复。
            addi sp, sp, -8*2
            sd   sp, 0*8(sp)

            # 裸函数不能依赖编译器保存参数，这里用 s1/s2 暂存 hart id
            # 和 first 标志，避免后续 jal 调用破坏 a0/a1。
            addi sp, sp, -8*2
            sd   s1, 0*8(sp)
            sd   s2, 1*8(sp)
            mv   s1, a0
            mv   s2, a1

            # first hart 负责初始化内存管理；其他 hart 只启用已有内核页表。
            beq  a1, zero, 1f
            addi sp, sp, -8*2
            sd   fp, 0*8(sp)
            sd   ra, 1*8(sp)
            addi fp, sp, 8*2
            jal  ra, {mm_init}
            ld   fp, 0*8(sp)
            ld   ra, 1*8(sp)
            addi sp, sp, 8*2
            j    2f
        1:
            addi sp, sp, -8*2
            sd   fp, 0*8(sp)
            sd   ra, 1*8(sp)
            addi fp, sp, 8*2
            jal  ra, {enable_kvm}
            ld   fp, 0*8(sp)
            ld   ra, 1*8(sp)
            addi sp, sp, 8*2
        2:
            # kernel_stack_bottom 由链接脚本定义。mm::init/enable_kvm 后，
            # 需要把当前低地址栈平移到高半区内核栈，否则后续 Rust 代码
            # 会在旧映射上继续压栈。
            la   t0, kernel_stack_bottom
            li   t1, {kernel_stack}
            sub  t2, t1, t0
            add  sp, sp, t2

            # 栈切换完成后再调用普通 Rust main，此时可以使用常规调用约定。
            addi sp, sp, -8*2
            sd   fp, 0*8(sp)
            sd   ra, 1*8(sp)
            addi fp, sp, 8*2
            mv   a0, s1
            mv   a1, s2
            jal  ra, {main}
            ld   fp, 0*8(sp)
            ld   ra, 1*8(sp)
            addi sp, sp, 8*2

            ld   s1, 0*8(sp)
            ld   s2, 1*8(sp)
            addi sp, sp, 8*2

            ld   sp, 0*8(sp)
            addi sp, sp, 8*2
            jr   ra
            ",
            kernel_stack = const Constant::KERNEL_STACK_BOTTOM,
            enable_kvm = sym enable_kvm,
            mm_init = sym mm::init,
            main = sym main
        )
    }
}

hal::define_entry!(pre_main);

