use hal::trap::{
    set_kernel_trap_entry, set_user_trap_entry, TrapContext, TrapContextHal, TrapType, TrapTypeHal,
};
use hal::util::backtrace;
use log::{info, warn};

hal::define_user_trap_handler!(user_trap_handler);

static USER_PAGE_FAULT_WARN_COUNT: AtomicUsize = AtomicUsize::new(0);

fn should_log_user_page_fault() -> bool {
    let count = USER_PAGE_FAULT_WARN_COUNT.fetch_add(1, Ordering::Relaxed) + 1;
    count <= 32 || count.is_power_of_two()
}

/// handle an interrupt, exception, or system call from user space
/// return true if it is syscall and has been interrupted
pub async fn user_trap_handler() -> bool {
    set_kernel_trap_entry();
    let (trap_type, epc) = TrapType::get_debug();
    unsafe { Instruction::enable_interrupt() };
    match trap_type {
        TrapType::Breakpoint => {
            let Some(task) = current_task().cloned() else {
                log::error!("[user_trap_handler] breakpoint without current task");
                return false;
            };
            log::warn!("[user_trap_handler] task {} break point", task.tid());
            // task.set_stopped();
            task.recv_sigs(SigInfo {
                si_signo: SIGTRAP,
                si_code: SigInfo::KERNEL,
                si_pid: None,
                ..Default::default()
            });
        }
        TrapType::Syscall => {
            let _sum = SumGuard::new();
            let Some(task) = current_task() else {
                log::error!("[user_trap_handler] syscall without current task");
                return false;
            };
            let cx = task.get_trap_cx();
            let syscall_id = cx.syscall_id();
            *cx.sepc() += 4;
            // get system call return value
            let result = syscall(
                cx.syscall_id(),
                [
                    cx.syscall_arg_nth(0),
                    cx.syscall_arg_nth(1),
                    cx.syscall_arg_nth(2),
                    cx.syscall_arg_nth(3),
                    cx.syscall_arg_nth(4),
                    cx.syscall_arg_nth(5),
                ],
            )
            .await;
            // // cx is changed during sys_exec, so we have to call it again
            // cx.save_to(0, cx.ret_nth(0));
            // report that the syscall is interrupt
            cx.set_ret_nth(0, result as usize);
            if result == -(SysError::EINTR as isize) && syscall_id != SYSCALL_GETPRIORITY as usize {
                log::debug!(
                    "[user_trap_handler] task {} syscall is interrupted",
                    cx.syscall_id()
                );
                return true;
            }
        }
        TrapType::StorePageFault(stval)
        | TrapType::InstructionPageFault(stval)
        | TrapType::LoadPageFault(stval) => {
            log::debug!("[user_trap_handler] encounter page fault, addr {stval:#x}",);

            let access_type = match trap_type {
                TrapType::StorePageFault(_) => PageFaultAccessType::WRITE,
                TrapType::LoadPageFault(_) => PageFaultAccessType::READ,
                TrapType::InstructionPageFault(_) => PageFaultAccessType::EXECUTE,
                _ => unreachable!(),
            };

            let Some(task) = current_task() else {
                log::error!("[user_trap_handler] page fault without current task");
                return false;
            };
            let res = task.with_mut_vm_space(|vm_space| {
                vm_space.handle_page_fault(VirtAddr::from(stval), access_type)
            });
            match res {
                Ok(()) => {}
                Err(()) => {
                    if should_log_user_page_fault() {
                        log::debug!(
                            "[user_trap_handler] task pid {}, tid {}, cannot handle page fault, addr {stval:#x} access_type: {access_type:?} epc: {epc:#x}",
                            task.pid(), task.tid()
                        );
                    }
                    task.recv_sigs(SigInfo {
                        si_signo: SIGSEGV,
                        si_code: SigInfo::KERNEL,
                        si_pid: None,
                        ..Default::default()
                    });
                }
            }
        }
        TrapType::IllegalInstruction(_) => {
            println!("[trap_handler] IllegalInstruction in application, kernel killed it.");
            // illegal instruction exit code
            let Some(task) = current_task() else {
                log::error!("[user_trap_handler] illegal instruction without current task");
                return false;
            };
            task.recv_sigs(SigInfo {
                si_signo: SIGILL,
                si_code: SigInfo::KERNEL,
                si_pid: None,
                ..Default::default()
            });
        }
        TrapType::Timer => {
            IRQ_COUNTER.lock().add_timer_irq_cnt();
            crate::timer::timer::TIMER_MANAGER.check();
            #[cfg(feature = "smp")]
            crate::processor::processor::current_processor().update_load_avg();
            set_next_trigger();
            yield_now().await;
        }
        TrapType::ExternalInterrupt => {
            let manager = crate::devices::DEVICE_MANAGER.lock();
            manager.handle_irq();
        }
        TrapType::Processed => {}
        trap => {
            let Some(task) = current_task() else {
                log::error!(
                    "[user_trap_handler] unsupported user trap {:?} without current task, epc {epc:#x}",
                    trap
                );
                return false;
            };
            log::warn!(
                "[user_trap_handler] task pid {}, tid {} unsupported trap {:?}, epc {epc:#x}; send SIGILL",
                task.pid(),
                task.tid(),
                trap
            );
            task.recv_sigs(SigInfo {
                si_signo: SIGILL,
                si_code: SigInfo::KERNEL,
                si_pid: None,
                ..Default::default()
            });
        }
    }
    false
    // println!("before trap_return");
}

