}

pub static MOUNT_RECORDS: SpinNoIrqLock<BTreeMap<String, MountRecord>> =
    SpinNoIrqLock::new(BTreeMap::new());

pub fn record_mount(source: &str, target: &str, fs_type: &str, flags: MountFlags) {
    MOUNT_RECORDS.lock().insert(
        target.to_string(),
        MountRecord {
            source: source.to_string(),
            fs_type: fs_type.to_string(),
            flags,
        },
    );
}

pub fn remove_mount_record(target: &str) -> bool {
    MOUNT_RECORDS.lock().remove(target).is_some()
}

pub fn is_recorded_mountpoint(target: &str) -> bool {
    MOUNT_RECORDS.lock().contains_key(target)
}

pub fn mount_records_snapshot() -> Vec<(String, MountRecord)> {
    MOUNT_RECORDS
        .lock()
        .iter()
        .map(|(path, record)| (path.clone(), record.clone()))
        .collect()
}

pub fn mount_flags_for_path(path: &str) -> MountFlags {
    let records = MOUNT_RECORDS.lock();
    let mut best_len = 0usize;
    let mut flags = MountFlags::empty();
    for (mount_path, record) in records.iter() {
        let inside_mount = path == mount_path
            || path
                .strip_prefix(mount_path.as_str())
                .is_some_and(|suffix| suffix.starts_with('/'));
        if inside_mount && mount_path.len() >= best_len {
            best_len = mount_path.len();
            flags = record.flags;
        }
    }
    flags
}

