/// unwrap first then call the method with the closure
macro_rules! generate_unwrap_with_methods {
    ($($name:ident : $ty:ty),+) => {
        paste::paste! {
            $(
                #[allow(unused)]
                /// with method for Shared<$ty>, takes a closure and returns a reference to the inner value
                pub fn [<unwrap_with_ $name>]<T>(&self, f: impl FnOnce(&$ty) -> T) -> Option<T> {
                    log::trace!("with_{}", stringify!($name));
                    let Some(shared) = self.$name.as_ref() else {
                        log::warn!("unwrap_with_{} called on processor {} before initialization", stringify!($name), self.id);
                        return None;
                    };
                    Some(f(&shared.lock()))
                }
                #[allow(unused)]
                /// with  mut method for Shared<$ty>, takes a closure and returns a mutable reference to the inner value
                pub fn [<unwrap_with_mut_ $name>]<T>(&mut self, f: impl FnOnce(&mut $ty) -> T) -> Option<T> {
                    log::trace!("with_mut_{}", stringify!($name));
                    let Some(shared) = self.$name.as_ref() else {
                        log::warn!("unwrap_with_mut_{} called on processor {} before initialization", stringify!($name), self.id);
                        return None;
                    };
                    Some(f(&mut shared.lock()))
                }
            )+
        }
    };
}

