#[derive(Clone, Copy, Debug)]
#[repr(C)]
pub struct TrapContext {
    /// user-to-kernel should save:
    /// general regs[0..31]
    pub(crate) x: [usize; 32],
    /// CSR sstatus      
    pub(crate) sstatus: Sstatus, // 32
    // pub sstatus: usize, // 32
    /// CSR sepc
    pub(crate) sepc: usize, // 33

    /// Unlike rCore-tutorial, we don't need to save
    /// trap_handler here, since we will trap back to kernel
    /// and go to trap handler by reloading kernel's ra(through __trap_from_user).
    // pub trap_handler: usize,

    /// kernel-to-user should save:
    ///
    pub(crate) kernel_sp: usize, // 34
    ///
    pub(crate) kernel_ra: usize, // 35
    ///
    pub(crate) kernel_s: [usize; 12], // 36 - 47
    ///
    pub(crate) kernel_fp: usize, // 48
    ///
    pub(crate) kernel_tp: usize, // 49
    /// float registers
    pub(crate) user_fx: FloatContext, 
    /// used in multi_core
    pub(crate) stored: usize,
    // /// used for signal, when using SA_RESTART flag, need to restore last user arg0
    // pub(crate) last_user_arg0: usize,
}

impl TrapContextHal for TrapContext {
    fn syscall_id(&self) -> usize {
        self.x[17]
    }

    fn syscall_arg_nth(&self, n: usize) -> usize {
        if n >= 6 {
            log::warn!("[TrapContext::syscall_arg_nth] invalid arg index {}", n);
            return 0;
        }
        self.x[10 + n]
    }

    fn arg_nth(&self, n: usize) -> usize {
        if n < 8 {
            self.x[10 + n]
        } else {
            log::warn!("[TrapContext::arg_nth] invalid arg index {}", n);
            0
        }
    }

    fn set_arg_nth(&mut self, n: usize, arg: usize) {
        if n < 8 {
            self.x[10 + n] = arg
        } else {
            log::warn!("[TrapContext::set_arg_nth] invalid arg index {}", n);
        }
    }

    fn sp(&mut self) -> &mut usize {
        &mut self.x[2]
    }

    fn sepc(&mut self) -> &mut usize {
        &mut self.sepc
    }

    fn app_init_context(
        entry: usize,
        sp: usize,
        argc: usize,
        argv: usize,
        envp: usize,
    ) -> Self {
        // set CPU privilege to User after trapping back
        unsafe {
            sstatus::set_spp(SPP::User);
            Instruction::disable_interrupt();
        }
        let mut cx = Self {
            x: [0; 32],
            sstatus: sstatus::read(),
            sepc: entry,
            // saved in ___restore
            kernel_sp: 0,
            kernel_ra: 0,
            kernel_s: [0; 12],
            kernel_fp: 0,
            kernel_tp: 0,
            user_fx: FloatContext::new(),
            stored: 0,
            // last_user_arg0: 0,
        };
        *cx.sp() = sp;
        cx.set_arg_nth(0, argc);
        cx.set_arg_nth(1, argv);
        cx.set_arg_nth(2, envp);
        cx
    }

    fn ret_nth(&self, n: usize) -> usize {
        if n < 2 {
            self.x[10 + n]
        } else {
            log::warn!("[TrapContext::ret_nth] invalid return index {}", n);
            0
        }
    }

    fn set_ret_nth(&mut self, n: usize, ret: usize) {
        if n < 2 {
            self.x[10 + n] = ret;
        } else {
            log::warn!("[TrapContext::set_ret_nth] invalid return index {}", n);
        }
    }

    fn save_to(&mut self, idx: usize, v: usize) {
        if idx != 0 {
            log::warn!("[TrapContext::save_to] invalid stored index {}", idx);
            return;

