/// Trait for block devices
/// which reads and writes data in the unit of blocks
pub trait BlockDevice: Send + Sync + Any {
    fn size(&self) -> u64;

    fn buffer_cache(&self) -> Option<Arc<BufferCache>>;

    fn block_size(&self) -> usize;

    /// Read data form block to buffer
    fn direct_read_block(&self, block_id: usize, buf: &mut [u8]);

    /// Write data from buffer to block
    fn direct_write_block(&self, block_id: usize, buf: &[u8]);

    /// Read a consecutive block range directly from the device.
    fn direct_read_blocks(&self, block_id: usize, buf: &mut [u8]) {
        let block_size = self.block_size();
        for (offset, chunk) in buf.chunks_mut(block_size).enumerate() {
            if chunk.len() == block_size {
                self.direct_read_block(block_id + offset, chunk);
            }
        }
    }

    /// Write a consecutive block range directly to the device.
    fn direct_write_blocks(&self, block_id: usize, buf: &[u8]) {
        let block_size = self.block_size();
        for (offset, chunk) in buf.chunks(block_size).enumerate() {
            if chunk.len() == block_size {
                self.direct_write_block(block_id + offset, chunk);
            }
        }
    }

    /// Flush pending device writes when the backend supports it.
    fn flush(&self) {}
}

