static TCP_IPERF_DEBUG_COUNTER: AtomicUsize = AtomicUsize::new(0);
static TCP_IPERF_POLL_DEBUG_COUNTER: AtomicUsize = AtomicUsize::new(0);

fn tcp_iperf_debug_enabled() -> bool {
    !option_env!("XCXOS_TCP_IPERF_DEBUG")
        .unwrap_or("")
        .is_empty()
