        .unwrap_or("")
        .is_empty()
}

fn is_iperf_debug_socket(local: Option<IpEndpoint>, remote: Option<IpEndpoint>) -> bool {
    if !tcp_iperf_debug_enabled() {
        return false;
    }
    match (local, remote) {
        (Some(local), Some(remote)) => local.port == 5001 || remote.port == 5001,
        _ => false,
    }
}

fn should_log_iperf_debug() -> bool {
    let count = TCP_IPERF_DEBUG_COUNTER.fetch_add(1, Ordering::Relaxed);
    count < 1024 || count % 4096 == 0
}

fn should_log_iperf_poll_debug() -> bool {
    let count = TCP_IPERF_POLL_DEBUG_COUNTER.fetch_add(1, Ordering::Relaxed);
    count < 256 || count % 4096 == 0
}

fn orphan_tcp_socket(handle: SocketHandle) {
    let mut orphans = ORPHANED_TCP_SOCKETS.lock();
    if !orphans.contains(&handle) {
        orphans.push(handle);
    }
}

pub fn reap_orphaned_tcp_sockets() {
    let handles = ORPHANED_TCP_SOCKETS.lock().clone();
    let mut reclaim = Vec::new();
    for handle in handles {
        let can_remove = SOCKET_SET.with_socket_mut::<tcp::Socket, _, _>(handle, |socket| {
            matches!(socket.state(), State::Closed | State::TimeWait)
        });
        if can_remove {
            reclaim.push(handle);
        }
    }
    if reclaim.is_empty() {
        return;
    }
    ORPHANED_TCP_SOCKETS
        .lock()
        .retain(|handle| !reclaim.contains(handle));
    for handle in reclaim {
        SOCKET_SET.remove(handle);
    }
}

