pub unsafe extern "C" fn _start() {
    #[cfg(target_arch = "riscv64")]
    core::arch::naked_asm!(
        "
        mv a0, sp
        jal ra, _rust_start
        "
    );
    #[cfg(target_arch = "loongarch64")]
    core::arch::naked_asm!(
        "
