//! Page Cache
//! each inode will hold a page cache
//! (todos): 1. radix tree to manage the offset to page
//! 2. ahead read

use core::{
    cmp,
    sync::atomic::{AtomicUsize, Ordering},
};

use crate::{fs::vfs::Inode, sync::mutex::SpinNoIrqLock};
use alloc::{collections::btree_map::BTreeMap, sync::Arc, vec::Vec};
// use hashbrown::HashMap;
use log::warn;

use super::page::{Page, PAGE_SIZE};

pub struct PageCache {
    /// from file offset(should be page aligned)
    /// to the cached page
    /// TODO: now use BTreeMap to flush data from low off to high off
    /// to avoid the 'Seek Beyond file size' problem
    /// should fs support this?
    pages: SpinNoIrqLock<BTreeMap<usize, Arc<Page>>>,
    /// the postion of EOF
    /// save it to prevent endless read
    /// notice that it may need to update when
    /// cache write, as it may lead to expand the file
    end: AtomicUsize,
}

impl PageCache {
    /// create a new Page Cache
    pub fn new() -> Self {
        Self {
            pages: SpinNoIrqLock::new(BTreeMap::new()),
            end: AtomicUsize::new(0usize),
        }
    }
    /// get the cache inner
    pub fn get_pages(&self) -> &SpinNoIrqLock<BTreeMap<usize, Arc<Page>>> {
        &self.pages
    }
    /// get the page at file offset
    pub fn get_page(&self, offset: usize) -> Option<Arc<Page>> {
        if offset % PAGE_SIZE != 0 {
            warn!("[PageCache::get_page] unaligned offset {offset:#x}");
            return None;
        }
        self.pages.lock().get(&offset).cloned()
    }
    /// insert the page at file offset
    pub fn insert_page(&self, offset: usize, page: Arc<Page>) {
        if offset % PAGE_SIZE != 0 {
            warn!("[PageCache::insert_page] unaligned offset {offset:#x}");
            return;
        }
        self.pages.lock().insert(offset, page);
    }
    pub fn update_end(&self, offset: usize) {
        let end = self.end.load(Ordering::Acquire);
        // log::info!("updated end ({:#x} {:#x}) => {:#x}", end, offset, cmp::max(end, offset));
        self.end.store(cmp::max(end, offset), Ordering::Release);
    }
    pub fn end(&self) -> usize {
        self.end.load(Ordering::Acquire)
    }
    /// flush all dirty pages
    pub fn flush(&self, inode: Arc<dyn Inode>) -> Result<(), i32> {
        log::debug!("start to flush all pages");
        let mut pages = self.pages.lock();
        let end = self.end();
        for (&offset, page) in pages.iter_mut() {
            if page.is_dirty() == false {
                continue;
            }
            if offset >= end {
                page.set_clean();
                continue;
            }
            let write_size = cmp::min(PAGE_SIZE, end - offset);
            inode.write_at(offset, &page.get_slice::<u8>()[..write_size])?;
            page.set_clean();
        }
        Ok(())
    }

    /// truncate the cache
    /// reduce the cache size if given size is smaller
    pub fn truncate(&self, tsize: usize) {
        if self.end() > tsize {
            let mut pages = self.pages.lock();
            let tail_offset = tsize / PAGE_SIZE * PAGE_SIZE;
            if tsize % PAGE_SIZE != 0 {
                if let Some(page) = pages.get(&tail_offset) {
                    page.zero_from(tsize % PAGE_SIZE);
                }
            }
            let remove_from = if tsize % PAGE_SIZE == 0 {
                tsize
            } else {
                tail_offset + PAGE_SIZE
            };
            let remove_page_idxs: Vec<usize> = pages
                .range(remove_from..)
                .map(|(&offset, _)| offset)
                .collect();
            for page_idx in remove_page_idxs {
                pages.remove(&page_idx);
            }
        }
        self.end.store(tsize, Ordering::Release);
    }
}

#![no_std]
