#[macro_use]
extern crate user_lib;

use user_lib::{
    execve, fork, kill, shutdown, sigaction, sleep, wait, waitpid, yield_, SignalAction,
    SignalFlags, SIGKILL, SIGTERM,
};

fn run_cmd(cmd: &str) {
    let pid = fork();
    if pid == 0 {
        // default use musl busybox
        #[cfg(target_arch = "riscv64")]
        execve(
            "/riscv/musl/busybox",
            &["busybox", "sh", "-c", cmd],
            &["PATH=/:/bin", "HOME=/home/chronix"],
        );

        #[cfg(target_arch = "loongarch64")]
        execve(
            "/loongarch/musl/busybox",
            &["busybox", "sh", "-c", cmd],
            &["PATH=/:/bin", "HOME=/home/chronix"],
        );
    } else {
        let mut result: i32 = 0;
        waitpid(pid as usize, &mut result);
    }
}

fn init_env() {
    #[cfg(target_arch = "riscv64")]
    run_cmd("[ -e /bin/ls ] || /riscv/musl/busybox --install /bin");
    #[cfg(target_arch = "loongarch64")]
    run_cmd("[ -e /bin/ls ] || /loongarch/musl/busybox --install /bin");
    // run_cmd("rm /bin/sh");
}

fn request_shutdown() -> ! {
    println!("[initproc] request shutdown");
    shutdown();
    kill(-1, SIGTERM);
    sleep(500);
    kill(-1, SIGKILL);
    loop {
        yield_();
    }
}

fn term_sig_handler(_signo: i32) {
    println!("[initproc] term_sig_handler");
    request_shutdown();
}

#[no_mangle]
fn main() -> i32 {
    init_env();
    println!("into user mode initproc");
    if fork() == 0 {
        println!("into user mode initproc fork");
        #[cfg(target_arch = "riscv64")]
        execve(
            "/riscv/musl/busybox",
            &["busybox", "sh"],
            &["PATH=/:/bin", "TERM=screen"],
        );
        #[cfg(target_arch = "loongarch64")]
        execve(
            "/loongarch/musl/busybox",
            &["busybox", "sh"],
            &["PATH=/:/bin", "TERM=screen"],
        );
        println!("[secondproc] execve busybox fail");
    } else {
        println!("into user mode initproc wait");
        let term_sig_action = SignalAction {
            handler: term_sig_handler as *const fn(i32) as usize,
            mask: SignalFlags::all(),
        };
        sigaction(SIGTERM, Some(&term_sig_action), None);
        loop {
            let mut exit_code: i32 = 0;
            let pid = wait(&mut exit_code);
            // -10: ECHILD
            if pid == -10 {
                println!("[initproc] no child process, shutdown");
                request_shutdown();
            }
            if exit_code != 0 {
                println!(
                    "[initproc] Released a zombie process, pid={}, exit_code={}",
                    pid, exit_code,
                );
            }
        }
    }
    0
}

