fn cancel_interruptible_wait(task: &Arc<TaskControlBlock>) {
    task.with_mut_sig_manager(|sig_manager| {
        sig_manager.wake_sigs = SigSet::empty();
    });
    task.set_running();
}

fn has_pending_wake_signal(task: &Arc<TaskControlBlock>) -> bool {
    task.with_sig_manager(|sig_manager| sig_manager.check_pending_flag(sig_manager.wake_sigs))
}

fn add_awaiter(
    fm: &mut FutexManager,
    task: &Arc<TaskControlBlock>,
    key: FutexHashKey,
    mask: u32,
) -> SysResult {
    task.set_interruptable();
    let wake_up_sigs = task.with_sig_manager(|s| !s.blocked_sigs);
    task.set_wake_up_sigs(wake_up_sigs);
    if has_pending_wake_signal(task) {
        cancel_interruptible_wait(task);
        return Err(SysError::EINTR);
    }
    let Some(waker) = task.waker().clone() else {
        cancel_interruptible_wait(task);
        return Err(SysError::EAGAIN);
    };
    fm.add_waiter(
        &key,
        FutexWaiter {
            tid: task.tid(),
            waker,
            mask,
        },
    );
    if has_pending_wake_signal(task) {
        fm.remove_waiter(&key, task.tid());
        cancel_interruptible_wait(task);
        return Err(SysError::EINTR);
    }
    Ok(0)
}

#[derive(Debug, Clone, Copy, Eq, PartialEq)]
enum FutexWaitExit {
    Woken,
    Interrupted,
    StillQueued,
}

fn finish_futex_wait(task: &Arc<TaskControlBlock>, key: &FutexHashKey) -> FutexWaitExit {
    let wake_up_sigs = task.with_mut_sig_manager(|sig_manager| {
        let wake_up_sigs = sig_manager.wake_sigs;
        sig_manager.wake_sigs = SigSet::empty();
        wake_up_sigs
    });
    let interrupted =
        task.with_sig_manager(|sig_manager| sig_manager.check_pending_flag(wake_up_sigs));
    let still_queued = futex_manager().remove_waiter(key, task.tid()).is_some();
    task.set_running();

    if interrupted {
        FutexWaitExit::Interrupted
    } else if still_queued {
        FutexWaitExit::StillQueued
    } else {
        FutexWaitExit::Woken
    }
}

