pub struct NetlinkSocket {
    inner: SpinNoIrqLock<NetlinkInner>,
    non_blocking: AtomicBool,
}

struct NetlinkInner {
    packets: VecDeque<Vec<u8>>,
    read_wakers: VecDeque<Waker>,
}

impl NetlinkSocket {
    pub fn new() -> Self {
        Self {
            inner: SpinNoIrqLock::new(NetlinkInner {
                packets: VecDeque::new(),
                read_wakers: VecDeque::new(),
            }),
            non_blocking: AtomicBool::new(false),
        }
    }

    pub fn set_nonblocking(&self) {
        self.non_blocking.store(true, Ordering::Release);
    }

    pub fn push_packet(&self, data: Vec<u8>) {
        let mut inner = self.inner.lock();
        inner.packets.push_back(data);
        while let Some(waker) = inner.read_wakers.pop_front() {
            waker.wake();
        }
    }

    pub async fn recv(&self, data: &mut [u8]) -> SockResult<usize> {
        NetlinkReadFuture { socket: self }.await?;
        let mut inner = self.inner.lock();
        let Some(packet) = inner.packets.pop_front() else {
            return Err(SysError::EAGAIN);
        };
        let len = data.len().min(packet.len());
        data[..len].copy_from_slice(&packet[..len]);
        Ok(len)
    }

    pub fn poll(&self) -> PollState {
        let inner = self.inner.lock();
        PollState {
            readable: !inner.packets.is_empty(),
            writable: true,
            hangup: false,
        }
    }
}

struct NetlinkReadFuture<'a> {
    socket: &'a NetlinkSocket,
}

impl Future for NetlinkReadFuture<'_> {
    type Output = SockResult<()>;

    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        let mut inner = self.socket.inner.lock();
        if !inner.packets.is_empty() {
            return Poll::Ready(Ok(()));
        }
        if current_task()
            .map(|task| {
                task.with_sig_manager(|sig_manager| {
                    let wakeable = !sig_manager.blocked_sigs | SigSet::SIGKILL | SigSet::SIGSTOP;
                    sig_manager.check_pending_flag(wakeable)
                })
            })
            .unwrap_or(false)
        {
            return Poll::Ready(Err(SysError::EINTR));
        }
        if self.socket.non_blocking.load(Ordering::Acquire) {
            return Poll::Ready(Err(SysError::EAGAIN));
        }
        if !inner
            .read_wakers
            .iter()
            .any(|waker| waker.will_wake(cx.waker()))
        {
            inner.read_wakers.push_back(cx.waker().clone());
        }
        Poll::Pending
    }
}

