fn validate_clone_flags(flags: CloneFlags) -> SysResult {
    let unsupported = CloneFlags::PIDFD
        | CloneFlags::NEWCGROUP
        | CloneFlags::NEWIPC
        | CloneFlags::NEWUSER
        | CloneFlags::NEWPID
        | CloneFlags::NEWNET;
    if flags.intersects(unsupported) {
        return Err(SysError::EOPNOTSUPP);
    }
    if flags.contains(CloneFlags::NEWNS) && flags.contains(CloneFlags::FS) {
        return Err(SysError::EINVAL);
    }
    if flags.contains(CloneFlags::NEWNS) {
        return Err(SysError::EOPNOTSUPP);
    }
    if flags.contains(CloneFlags::SIGHAND) && !flags.contains(CloneFlags::VM) {
        return Err(SysError::EINVAL);
    }
    if flags.contains(CloneFlags::THREAD)
        && !(flags.contains(CloneFlags::SIGHAND) && flags.contains(CloneFlags::VM))
    {
        return Err(SysError::EINVAL);
    }
    Ok(0)
}

