impl PidFdFile {
    fn new(target: Arc<TaskControlBlock>, flags: u32) -> Arc<Self> {
        let dentry = TmpDentry::new("pidfd", None);
        let inode = TmpSysInode::new(InodeMode::FILE, Arc::new(EmptyFile {}));
        dentry.set_inode(inode);

        let mut open_flags = OpenFlags::empty();
        if flags & PIDFD_NONBLOCK != 0 {
            open_flags.insert(OpenFlags::O_NONBLOCK);
        }

        Arc::new(Self {
            inner: FileInner {
                dentry,
                offset: AtomicUsize::new(0),
                flags: SpinNoIrqLock::new(open_flags),
            },
            target,
        })
    }

    fn target(&self) -> Arc<TaskControlBlock> {
        self.target.clone()
    }

    fn target_exited(&self) -> bool {
        self.target.is_zombie() && self.target.thread_group.lock().get_alive() == 0
    }
}

