fn parse_shebang(header: &[u8]) -> Option<(String, Option<String>)> {
    if !header.starts_with(b"#!") {
        return None;
    }
    let end = header
        .iter()
        .position(|&b| b == b'\n')
        .unwrap_or(header.len());
    let mut line = &header[2..end];
    if line.ends_with(b"\r") {
        line = &line[..line.len() - 1];
    }
    while matches!(line.first(), Some(b' ' | b'\t')) {
        line = &line[1..];
    }
    if line.is_empty() {
        return None;
    }

    let interp_end = line
        .iter()
        .position(|&b| b == b' ' || b == b'\t')
        .unwrap_or(line.len());
    let interp = String::from_utf8(line[..interp_end].to_vec()).ok()?;

    let mut arg = &line[interp_end..];
    while matches!(arg.first(), Some(b' ' | b'\t')) {
        arg = &arg[1..];
    }
    let arg = if arg.is_empty() {
        None
    } else {
        Some(String::from_utf8(arg.to_vec()).ok()?)
    };

    Some((interp, arg))
}

