fn dma_abort(reason: &str) -> ! {
    log::error!("[VirtioHal] {}", reason);
    crate::executor::os_send_shutdown();
    loop {
        core::hint::spin_loop();
    }
}

fn dma_page_count(len: usize) -> usize {
    if len == 0 {
        dma_abort("zero-length DMA share request");
    }
    (len - 1 + Constant::PAGE_SIZE) >> Constant::PAGE_SIZE_BITS
}

unsafe impl virtio_drivers::Hal for VirtioHal {
    fn dma_alloc(
        pages: usize,
        _direction: BufferDirection,
    ) -> (virtio_drivers::PhysAddr, NonNull<u8>) {
        info!("dma_alloc");
        let Some(frame) = frames_alloc_clean(pages) else {
            dma_abort("failed to allocate clean DMA frames");
        };
        let ppn_base = frame.range_ppn.start;
        core::mem::forget(frame);
        let pa: PhysAddr = ppn_base.start_addr();
        // Safety: frame allocation returned a live, page-aligned physical frame range.
        (pa.0, unsafe { NonNull::new_unchecked(pa.get_mut::<u8>()) })
    }

    unsafe fn dma_dealloc(
        paddr: virtio_drivers::PhysAddr,
        _vaddr: NonNull<u8>,
        pages: usize,
    ) -> i32 {
        info!("dma_dealloc");
        let pa = PhysAddr::from(paddr);
        let ppn_base: PhysPageNum = pa.floor();
        frames_dealloc(ppn_base..ppn_base + pages);
        0
    }

    unsafe fn mmio_phys_to_virt(paddr: virtio_drivers::PhysAddr, _size: usize) -> NonNull<u8> {
        // Safety: virtio transport calls this only for MMIO ranges discovered from the device tree.
        NonNull::new_unchecked(PhysAddr::from(paddr).get_mut::<u8>())
    }

    unsafe fn share(buffer: NonNull<[u8]>, direction: BufferDirection) -> virtio_drivers::PhysAddr {
        let buffer = buffer.as_ref();
        let cnt = dma_page_count(buffer.len());
        let Some(frames) = frames_alloc(cnt) else {
            dma_abort("failed to allocate shared DMA frames");
        };
        match direction {
            BufferDirection::DriverToDevice | BufferDirection::Both => {
                frames.range_ppn.get_slice_mut()[..buffer.len()].copy_from_slice(buffer);
            }
            BufferDirection::DeviceToDriver => {}
        }
        let pa = frames.range_ppn.start.start_addr().0;
        core::mem::forget(frames);
        pa
    }

    unsafe fn unshare(
        paddr: virtio_drivers::PhysAddr,
        mut buffer: NonNull<[u8]>,
        direction: BufferDirection,
    ) {
        let buffer = buffer.as_mut();
        let ppn_start = PhysAddr::from(paddr).floor();
        let ppn_end = PhysAddr::from(paddr + buffer.len()).ceil();
        let range_ppn = ppn_start..ppn_end;
        match direction {
            BufferDirection::DeviceToDriver | BufferDirection::Both => {
                buffer.copy_from_slice(&range_ppn.get_slice()[..buffer.len()]);
            }
            BufferDirection::DriverToDevice => {}
        }
        frames_dealloc(range_ppn);
    }
}

